//! # BCC-lattice voxel carve — opt-in, default-off analog of the E_8 recipe.
//!
//! [`crate::holographic_reconstruction`] carves a **cubic** ℤ³ voxel grid
//! ([`crate::holographic_reconstruction::VoxelCoord`]). Cubic ℤ³ is the WORST
//! 3-D lattice quantizer: G(ℤ³) = 1/12. The optimal 3-D lattice quantizer is
//! the body-centred cubic lattice BCC = A₃* (G(BCC) ≈ 0.078543, ~5.7% lower
//! MSE per sample, equivalently ~28% fewer samples for equal fidelity). BCC is
//! to 3-D what E_8 is to 8-D — but E_8 itself is 8-D and cannot tile a literal
//! 3-D carve, so BCC ([`crate::bcc_voxel::nearest_bcc`]) is the correct analog
//! here. (See `bcc_voxel.rs` for the certified decoder.)
//!
//! ## The 3-D recipe vs the high-D E_8 recipe (the honest difference)
//!
//! The E_8 "cell-filling" precondition (center + decorrelated high-D data) is
//! a HIGH-DIMENSIONAL statement: E_8's edge is anisotropy of the Voronoi cell
//! at d=8. In 3-D the BCC edge is structural and unconditional — it holds for
//! ANY input distribution that spreads across multiple cells, because the BCC
//! Voronoi cell (truncated octahedron) is strictly rounder than the ℤ³ cube
//! regardless of correlation. There is no DC-centring step: a voxel carve is
//! already in absolute world coordinates, and the body-centre coset is what
//! buys the win, not a mean removal. So this module measures **carve fidelity
//! and effective sample count BCC vs cubic** at a matched grid step, NOT a
//! cell-filling characterization (that diagnostic belongs to the E_8/high-D
//! targets).
//!
//! ## Additive + default-off
//!
//! [`CarveLattice::Cubic`] (default) reproduces the existing cubic carve
//! coordinate snap byte-for-byte. [`CarveLattice::Bcc`] snaps each sample's
//! continuous 3-D coordinate onto the nearest BCC point before voxelizing.
//! The existing [`crate::holographic_reconstruction::SovereignSieve`] is left
//! UNTOUCHED; a caller that wants the lower-error carve routes its sample
//! coordinates through [`snap_carve_coord`] / [`CarveConfig`] here.

#![allow(dead_code)]

use crate::bcc_voxel::{bcc_error_sq, cubic_error_sq, nearest_bcc};
use crate::holographic_reconstruction::VoxelCoord;

/// Which lattice the voxel carve snaps continuous sample coordinates onto.
/// Additive + opt-in.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Default)]
pub enum CarveLattice {
    /// Cubic ℤ³ — round each coordinate. The DEFAULT; byte-for-byte identical
    /// to the existing `holographic_reconstruction` carve snap.
    #[default]
    Cubic,
    /// Body-centred cubic — snap to the nearest BCC point (cubic grid ∪ body
    /// centres). Lower quantization error (~5.7%) / ~28% fewer samples at
    /// equal fidelity. Opt-in only.
    Bcc,
}

/// Opt-in carve config. `use_bcc_carve` defaults to `false` — the default
/// path is the unchanged cubic carve.
#[derive(Clone, Copy, Debug, Default)]
pub struct CarveConfig {
    /// `false` (default) ⇒ cubic ℤ³ snap. `true` ⇒ BCC snap.
    pub use_bcc_carve: bool,
    /// Carve grid step (world units per cubic cell edge). Cubic and BCC use
    /// the SAME step so the comparison is at equal grid resolution.
    pub step: f32,
}

impl CarveConfig {
    pub fn lattice(&self) -> CarveLattice {
        if self.use_bcc_carve {
            CarveLattice::Bcc
        } else {
            CarveLattice::Cubic
        }
    }
}

/// A snapped carve coordinate. Cubic carves land on integer `VoxelCoord`
/// directly. BCC carves can land on a body centre (a half-integer in cell
/// units) which we represent in DOUBLED integer units (`*2`) so both cosets
/// are exact — the `BccCoord` convention. `voxel` is the integer cubic-cell
/// the sample falls in (for indexing the existing voxel map); `half` carries
/// the doubled BCC coordinate when on the BCC lattice.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct SnappedCarve {
    /// Integer cubic-cell coordinate (floor of the snapped point) — drop-in
    /// for the existing `VoxelCoord`-keyed voxel map.
    pub voxel: VoxelCoord,
    /// Doubled BCC coordinate (`2·snapped`). For a cubic carve all components
    /// are even; for a BCC body-centre coset all are odd. Lets a caller carve
    /// the body-centre coset distinctly when it wants the full BCC resolution.
    pub doubled: [i64; 3],
}

/// Snap a continuous world coordinate `(x,y,z)` (already in CARVE units,
/// i.e. divided by `step` upstream) onto the configured lattice.
///
/// Cubic: round each component (byte-for-byte the default carve snap).
/// BCC: nearest BCC point via the certified [`nearest_bcc`] decoder.
pub fn snap_carve_coord(p: [f32; 3], cfg: &CarveConfig) -> SnappedCarve {
    match cfg.lattice() {
        CarveLattice::Cubic => {
            let xi = p[0].round() as i32;
            let yi = p[1].round() as i32;
            let zi = p[2].round() as i32;
            SnappedCarve {
                voxel: VoxelCoord {
                    x: xi,
                    y: yi,
                    z: zi,
                },
                doubled: [xi as i64 * 2, yi as i64 * 2, zi as i64 * 2],
            }
        }
        CarveLattice::Bcc => {
            let q = nearest_bcc([p[0] as f64, p[1] as f64, p[2] as f64]);
            // Doubled coords: even ⇒ cubic point, odd ⇒ body centre.
            // The owning integer cubic cell is floor(snapped) = doubled/2 with
            // .5 (body centre) flooring down toward its cube origin.
            let vx = (q.x2 as f64 / 2.0).floor() as i32;
            let vy = (q.y2 as f64 / 2.0).floor() as i32;
            let vz = (q.z2 as f64 / 2.0).floor() as i32;
            SnappedCarve {
                voxel: VoxelCoord {
                    x: vx,
                    y: vy,
                    z: vz,
                },
                doubled: [q.x2, q.y2, q.z2],
            }
        }
    }
}

/// Carve-fidelity comparison over a set of continuous sample coordinates (in
/// carve units): mean squared snap error for cubic vs BCC, plus the distinct
/// occupied-cell counts (proxy for "samples needed for this fidelity").
#[derive(Clone, Debug)]
pub struct CarveFidelityReport {
    pub n: usize,
    /// Mean squared snap error under cubic ℤ³.
    pub cubic_mse: f64,
    /// Mean squared snap error under BCC.
    pub bcc_mse: f64,
    /// Distinct cubic cells occupied (the cubic carve's effective resolution).
    pub cubic_cells: usize,
    /// Distinct BCC points occupied (BCC's effective resolution — includes the
    /// body-centre coset, so finer for the same step).
    pub bcc_points: usize,
    /// `1 - bcc_mse/cubic_mse` as a percentage. Positive ⇒ BCC wins.
    pub pct_lower_error: f64,
}

/// Measure carve fidelity of BCC vs cubic over `samples` (continuous carve
/// coords). Both snap at the SAME implicit unit step (the samples are assumed
/// pre-scaled). The squared snap errors come from the certified
/// [`bcc_error_sq`] / [`cubic_error_sq`].
pub fn carve_fidelity(samples: &[[f32; 3]]) -> CarveFidelityReport {
    let n = samples.len();
    let mut cubic_acc = 0.0_f64;
    let mut bcc_acc = 0.0_f64;
    let mut cubic_cells = std::collections::HashSet::new();
    let mut bcc_points = std::collections::HashSet::new();
    for s in samples {
        let x = [s[0] as f64, s[1] as f64, s[2] as f64];
        cubic_acc += cubic_error_sq(&x);
        bcc_acc += bcc_error_sq(&x);
        cubic_cells.insert([
            x[0].round() as i64,
            x[1].round() as i64,
            x[2].round() as i64,
        ]);
        let q = nearest_bcc(x);
        bcc_points.insert([q.x2, q.y2, q.z2]);
    }
    let cubic_mse = if n > 0 { cubic_acc / n as f64 } else { 0.0 };
    let bcc_mse = if n > 0 { bcc_acc / n as f64 } else { 0.0 };
    let pct_lower_error = if cubic_mse > 0.0 {
        (1.0 - bcc_mse / cubic_mse) * 100.0
    } else {
        0.0
    };
    CarveFidelityReport {
        n,
        cubic_mse,
        bcc_mse,
        cubic_cells: cubic_cells.len(),
        bcc_points: bcc_points.len(),
        pct_lower_error,
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::e8_quantizer::SplitMix64;

    /// Default config = cubic carve, byte-for-byte the existing snap (round).
    #[test]
    fn default_is_cubic_carve_byte_for_byte() {
        let cfg = CarveConfig::default();
        assert!(!cfg.use_bcc_carve);
        assert_eq!(cfg.lattice(), CarveLattice::Cubic);
        // The cubic snap must equal a plain round-to-VoxelCoord.
        let p = [3.4_f32, -2.6, 7.51];
        let s = snap_carve_coord(p, &cfg);
        assert_eq!(s.voxel, VoxelCoord { x: 3, y: -3, z: 8 });
        // Doubled coords all even for cubic.
        assert!(
            s.doubled.iter().all(|c| c % 2 == 0),
            "cubic ⇒ all-even doubled"
        );
    }

    /// BCC carve snaps to a valid BCC point (all-even cubic OR all-odd body
    /// centre in doubled coords).
    #[test]
    fn bcc_carve_snaps_to_lattice_point() {
        let cfg = CarveConfig {
            use_bcc_carve: true,
            step: 1.0,
        };
        let mut rng = SplitMix64::new(0xB0CC_CA12);
        for _ in 0..5000 {
            let v = rng.next_vec8(8.0);
            let s = snap_carve_coord([v[0] as f32, v[1] as f32, v[2] as f32], &cfg);
            let parity = s.doubled[0].rem_euclid(2);
            assert!(
                s.doubled.iter().all(|c| c.rem_euclid(2) == parity),
                "BCC point: all-even or all-odd doubled, got {:?}",
                s.doubled
            );
        }
    }

    /// FIDELITY — lead with this. BCC must carve with lower snap error than
    /// cubic at the same grid step, and resolve more distinct points (the
    /// body-centre coset). This is the unconditional 3-D structural win, NOT a
    /// cell-filling-gated claim.
    #[test]
    fn bcc_carve_fidelity_beats_cubic() {
        let mut rng = SplitMix64::new(0xCA77_BCC0);
        const N: usize = 50_000;
        let mut samples = Vec::with_capacity(N);
        for _ in 0..N {
            let v = rng.next_vec8(8.0);
            samples.push([v[0] as f32, v[1] as f32, v[2] as f32]);
        }
        let r = carve_fidelity(&samples);
        println!(
            "\n[BCC carve fidelity] N={}\n  \
             cubic ℤ³ MSE = {:.6}  ({} distinct cells)\n  \
             BCC      MSE = {:.6}  ({} distinct points)\n  \
             => BCC {:.2}% lower snap error; BCC resolves {:.2}x the points",
            r.n,
            r.cubic_mse,
            r.cubic_cells,
            r.bcc_mse,
            r.bcc_points,
            r.pct_lower_error,
            r.bcc_points as f64 / r.cubic_cells.max(1) as f64,
        );
        assert!(r.bcc_mse < r.cubic_mse, "BCC must carve with lower error");
        // The theoretical raw-MSE edge of BCC over cubic ≈ 5.7% (at equal cell
        // count) but per-SAMPLE snap error at equal STEP is larger because BCC
        // has 2 points per unit cube — denser, so each sample is closer.
        assert!(
            r.pct_lower_error > 5.0,
            "expected a clear BCC edge, got {:.2}%",
            r.pct_lower_error
        );
    }

    /// COLD vs WARM timing on the carve snap.
    #[test]
    fn bench_carve_cold_warm() {
        let mut rng = SplitMix64::new(0xB0DA_CA7E);
        const N: usize = 200_000;
        let mut samples = Vec::with_capacity(N);
        for _ in 0..N {
            let v = rng.next_vec8(16.0);
            samples.push([v[0] as f32, v[1] as f32, v[2] as f32]);
        }
        let cubic_cfg = CarveConfig {
            use_bcc_carve: false,
            step: 1.0,
        };
        let bcc_cfg = CarveConfig {
            use_bcc_carve: true,
            step: 1.0,
        };
        let run = |cfg: &CarveConfig| -> std::time::Duration {
            let t = std::time::Instant::now();
            let mut acc = 0i64;
            for s in &samples {
                let snap = snap_carve_coord(*s, cfg);
                acc = acc.wrapping_add(snap.doubled[0]);
            }
            std::hint::black_box(acc);
            t.elapsed()
        };
        let cubic_cold = run(&cubic_cfg);
        let bcc_cold = run(&bcc_cfg);
        let cubic_warm = run(&cubic_cfg);
        let bcc_warm = run(&bcc_cfg);
        println!(
            "\n[carve snap bench] N={N}\n  \
             CUBIC: COLD {cubic_cold:?} WARM {cubic_warm:?}\n  \
             BCC:   COLD {bcc_cold:?} WARM {bcc_warm:?}",
        );
        // Both must complete; BCC is ~2x the work (two cosets) but O(1)/sample.
        assert!(bcc_warm.as_nanos() > 0 && cubic_warm.as_nanos() > 0);
    }
}
